import Link from "next/link";
import { cookies, headers } from "next/headers";
import crypto from "node:crypto";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";

/**
 * Server-rendered login form. We generate the CSRF token here AND seed the
 * matching __Host-authjs.csrf-token cookie in the same response. NextAuth
 * uses the double-submit cookie pattern: cookie value is
 * `${token}|HMAC_SHA256_HEX(token, AUTH_SECRET)`. Doing it server-side
 * eliminates the race where the browser submits the form before /api/auth/csrf
 * has been hit.
 */
export const dynamic = "force-dynamic";

export default async function LoginPage({
  searchParams,
}: {
  searchParams: Promise<{ error?: string }>;
}) {
  const sp = await searchParams;
  const h = await headers();
  const c = await cookies();
  const proto = (h.get("x-forwarded-proto") || "https").toLowerCase();
  const isSecure = proto === "https";
  const cookieName = isSecure ? "__Host-authjs.csrf-token" : "authjs.csrf-token";

  const secret = process.env.AUTH_SECRET || process.env.NEXTAUTH_SECRET || "";
  let token = "";
  let cookieVal = "";
  const existing = c.get(cookieName)?.value;
  if (existing && existing.includes("|")) {
    [token] = existing.split("|");
    cookieVal = existing;
  } else {
    token = crypto.randomBytes(32).toString("hex");
    const hash = crypto.createHmac("sha256", secret).update(token).digest("hex");
    cookieVal = `${token}|${hash}`;
    c.set(cookieName, cookieVal, {
      httpOnly: true,
      secure: isSecure,
      sameSite: "lax",
      path: "/",
    });
  }

  return (
    <div className="container mx-auto px-6 py-16 max-w-md">
      <Card>
        <CardHeader>
          <CardTitle data-testid="login-title">Sign in</CardTitle>
          <CardDescription>Use your Inkwell credentials.</CardDescription>
        </CardHeader>
        <CardContent>
          <form className="space-y-4" method="POST" action="/api/auth/callback/credentials">
            <input type="hidden" name="csrfToken" value={token} />
            <input type="hidden" name="callbackUrl" value="/dashboard" />
            <Input type="email" name="email" placeholder="you@email.com" required data-testid="login-email" />
            <Input type="password" name="password" placeholder="Password" required data-testid="login-password" />
            {sp?.error && (
              <p className="text-sm text-destructive" data-testid="login-error">
                Sign-in failed. Check your email and password.
              </p>
            )}
            <Button type="submit" className="w-full" data-testid="login-submit">Sign in</Button>
            <p className="text-sm text-muted-foreground text-center">
              No account?{" "}
              <Link href="/register" className="text-primary underline-offset-4 hover:underline" data-testid="login-to-register">Register</Link>
            </p>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}
